Функция НайтиДействующийДоговор(Контрагент, ДатаСреза) Экспорт

    Запрос = Новый Запрос;
    Запрос.Текст =
        "ВЫБРАТЬ
         | Договоры.Ссылка
         |ИЗ
         | Справочник.Договоры КАК Договоры
         |ГДЕ
         | Договоры.Владелец = &Владелец
         | И Договоры.ДатаНачала <= &ДатаСреза
         | И (Договоры.ДатаОкончания >= &ДатаСреза ИЛИ Договоры.ДатаОкончания = ЗНАЧЕНИЕ(ДАТА.ПустаяДата()))
         |УПОРЯДОЧИТЬ ПО Договоры.ДатаНачала УБЫВ";

    Запрос.УстановитьПараметр("Владелец", Контрагент);
    Запрос.УстановитьПараметр("ДатаСреза", ДатаСреза);

    Результат = Запрос.Выполнить();
    Выборка = Результат.Выбрать();

    Если Выборка.Следующий() Тогда
        Возврат Выборка.Ссылка;
    Иначе
        Возврат Неопределено;
    КонецЕсли;

КонецФункции
